declare(strict_types=1);require __DIR__.'/bootstrap.php';use VP3\Mail\MailerFactory;$complete=false;if(vp3_method()==='POST'){vp3_verify_csrf();$email=strtolower(vp3_input('email'));if(filter_var($email,FILTER_VALIDATE_EMAIL)&&vp3_db_available()&&vp3_rate_limit('password-reset:'.$email,3,3600)){$stmt=vp3_db()->prepare("SELECT id FROM customers WHERE email=? AND status='active' LIMIT 1");$stmt->execute([$email]);$id=(int)($stmt->fetchColumn()?:0);if($id>0){$token=vp3_secure_token();$hash=vp3_hash_token($token);vp3_db()->prepare('INSERT INTO password_resets (customer_id,token_hash,expires_at,created_at) VALUES (?,?,DATE_ADD(NOW(),INTERVAL 30 MINUTE),NOW())')->execute([$id,$hash]);$url=vp3_url('reset-password.php?token='.rawurlencode($token));MailerFactory::make()->send($email,'Reset your VP3 Media Group password',"Reset your password: {$url}\n\nThis link expires in 30 minutes.");vp3_audit('customer',$id,'customer.password_reset_requested','customer',(string)$id);}}$complete=true;}$pageTitle='Forgot Password';$pageDescription='Request a secure VP3 account password reset.';$bodyClass='auth-page';require VP3_ROOT.'/includes/header.php';?>
<section class="auth-layout compact-auth">
  <div class="auth-visual"><img src="<?=vp3_e(vp3_url('assets/images/site/password-recovery.svg'))?>" alt="Secure password recovery with a lock, key, and verified email"><div class="auth-visual-copy"><span class="eyebrow">Secure recovery</span><h2>Regain access without exposing account information.</h2></div></div>
  <div class="auth-panel"><div class="auth-panel-inner"><span class="eyebrow">Account recovery</span><h1>Reset your password.</h1><?php if($complete):?><div class="recovery-success"><span>✓</span><h2>Check your email.</h2><p>If an eligible account exists, reset instructions have been queued. The secure link expires in 30 minutes.</p><a class="button secondary auth-submit" href="login.php">Return to sign in</a></div><?php else:?><p class="auth-intro">Enter your account email. For security, the response will not reveal whether an account exists.</p><form method="post"><?=vp3_csrf_field()?><div class="field"><label for="email">Email address</label><input id="email" name="email" type="email" required autocomplete="email" value="<?=vp3_e((string)($_POST['email']??''))?>"></div><button class="button auth-submit" type="submit">Send reset instructions</button></form><p class="auth-switch">Remembered your password? <a href="login.php">Return to sign in</a></p><div class="security-note"><b>Security note</b><span>Reset requests are rate limited and use expiring, hashed tokens.</span></div><?php endif;?></div></div>
